# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import os
import json
import uuid
import base64
from collections import Counter
from io import BytesIO
from datetime import datetime

from flask import Flask, request, jsonify
import numpy as np
from PIL import Image
import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import Dataset, DataLoader
import torchvision.transforms as transforms
import torchvision.models as models
import threading

app = Flask(__name__)

# In-memory storage
image_store = {}       # image_id -> {"data": base64_str, "filename": str, "uploaded_at": str}
annotations = {}       # image_id -> {annotator_id: label}
aggregated_labels = {} # image_id -> {"label": str, "confidence": float, "num_votes": int}
label_classes = set()  # set of all unique labels
model_status = {"status": "not_trained", "accuracy": None, "trained_at": None, "num_images": 0, "num_classes": 0}
trained_model = None
label_to_idx = {}
idx_to_label = {}

# Lock for thread safety
lock = threading.Lock()


class LabeledImageDataset(Dataset):
    """Dataset for labeled images."""

    def __init__(self, images, labels, label_to_idx, transform=None):
        self.images = images
        self.labels = labels
        self.label_to_idx = label_to_idx
        self.transform = transform or transforms.Compose([
            transforms.Resize((224, 224)),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])

    def __len__(self):
        return len(self.images)

    def __getitem__(self, idx):
        img_data = base64.b64decode(self.images[idx])
        img = Image.open(BytesIO(img_data)).convert("RGB")
        img = self.transform(img)
        label = self.label_to_idx[self.labels[idx]]
        return img, label


class ImageClassifier(nn.Module):
    """Simple image classifier based on ResNet18."""

    def __init__(self, num_classes):
        super().__init__()
        self.backbone = models.resnet18(weights=None)
        num_features = self.backbone.fc.in_features
        self.backbone.fc = nn.Linear(num_features, num_classes)

    def forward(self, x):
        return self.backbone(x)


def aggregate_labels_majority_vote(image_id):
    """Aggregate labels for an image using majority voting."""
    if image_id not in annotations or len(annotations[image_id]) == 0:
        return None

    votes = list(annotations[image_id].values())
    counter = Counter(votes)
    most_common_label, most_common_count = counter.most_common(1)[0]
    total_votes = len(votes)
    confidence = most_common_count / total_votes

    result = {
        "label": most_common_label,
        "confidence": confidence,
        "num_votes": total_votes,
        "vote_distribution": dict(counter)
    }
    aggregated_labels[image_id] = result
    return result


def aggregate_all_labels():
    """Re-aggregate labels for all images."""
    for image_id in annotations:
        aggregate_labels_majority_vote(image_id)


def train_model_on_labeled_data(epochs=10, batch_size=16, learning_rate=0.001):
    """Train model on aggregated labeled data."""
    global trained_model, model_status, label_to_idx, idx_to_label

    # Collect images with aggregated labels
    images = []
    labels = []

    for image_id, label_info in aggregated_labels.items():
        if image_id in image_store:
            images.append(image_store[image_id]["data"])
            labels.append(label_info["label"])

    if len(images) == 0:
        return {"error": "No labeled images available for training"}

    unique_labels = sorted(set(labels))
    if len(unique_labels) < 2:
        return {"error": "Need at least 2 classes to train. Currently have: " + str(len(unique_labels))}

    label_to_idx = {label: idx for idx, label in enumerate(unique_labels)}
    idx_to_label = {idx: label for label, idx in label_to_idx.items()}
    num_classes = len(unique_labels)

    dataset = LabeledImageDataset(images, labels, label_to_idx)
    dataloader = DataLoader(dataset, batch_size=batch_size, shuffle=True, num_workers=0)

    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    model = ImageClassifier(num_classes).to(device)
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=learning_rate)

    model.train()
    total_loss = 0
    total_correct = 0
    total_samples = 0

    for epoch in range(epochs):
        epoch_loss = 0
        epoch_correct = 0
        epoch_samples = 0

        for batch_images, batch_labels in dataloader:
            batch_images = batch_images.to(device)
            batch_labels = batch_labels.to(device)

            optimizer.zero_grad()
            outputs = model(batch_images)
            loss = criterion(outputs, batch_labels)
            loss.backward()
            optimizer.step()

            _, predicted = torch.max(outputs, 1)
            epoch_correct += (predicted == batch_labels).sum().item()
            epoch_samples += batch_labels.size(0)
            epoch_loss += loss.item() * batch_labels.size(0)

        total_loss = epoch_loss / epoch_samples
        total_correct = epoch_correct
        total_samples = epoch_samples

    training_accuracy = total_correct / total_samples if total_samples > 0 else 0

    trained_model = model
    model_status = {
        "status": "trained",
        "training_accuracy": round(training_accuracy, 4),
        "trained_at": datetime.utcnow().isoformat(),
        "num_images": len(images),
        "num_classes": num_classes,
        "classes": unique_labels,
        "epochs": epochs,
        "final_loss": round(total_loss, 4),
        "device": str(device)
    }

    return model_status


