@app.route("/health", methods=["GET"])
def health_check():
    """Health check endpoint."""
    return jsonify({
        "status": "healthy",
        "total_images": len(image_store),
        "total_annotations": sum(len(v) for v in annotations.values()),
        "total_aggregated": len(aggregated_labels),
        "model_status": model_status["status"]
    })


@app.route("/images", methods=["POST"])
def upload_image():
    """Upload an image for labeling."""
    if "image" in request.files:
        file = request.files["image"]
        img_data = base64.b64encode(file.read()).decode("utf-8")
        filename = file.filename or "unknown"
    elif request.is_json:
        data = request.get_json()
        img_data = data.get("image_base64")
        filename = data.get("filename", "unknown")
        if not img_data:
            return jsonify({"error": "No image data provided"}), 400
    else:
        return jsonify({"error": "No image provided. Send as file or base64 JSON."}), 400

    # Validate it's a valid image
    try:
        img = Image.open(BytesIO(base64.b64decode(img_data)))
        img.verify()
    except Exception as e:
        return jsonify({"error": f"Invalid image data: {str(e)}"}), 400

    image_id = str(uuid.uuid4())

    with lock:
        image_store[image_id] = {
            "data": img_data,
            "filename": filename,
            "uploaded_at": datetime.utcnow().isoformat()
        }
        annotations[image_id] = {}

    return jsonify({
        "image_id": image_id,
        "filename": filename,
        "message": "Image uploaded successfully"
    }), 201


@app.route("/images", methods=["GET"])
def list_images():
    """List all images with their annotation status."""
    result = []
    for image_id, img_info in image_store.items():
        num_annotations = len(annotations.get(image_id, {}))
        agg = aggregated_labels.get(image_id)
        result.append({
            "image_id": image_id,
            "filename": img_info["filename"],
            "uploaded_at": img_info["uploaded_at"],
            "num_annotations": num_annotations,
            "aggregated_label": agg["label"] if agg else None,
            "confidence": agg["confidence"] if agg else None
        })
    return jsonify({"images": result, "total": len(result)})


@app.route("/images/<image_id>", methods=["GET"])
def get_image(image_id):
    """Get image details including annotations."""
    if image_id not in image_store:
        return jsonify({"error": "Image not found"}), 404

    img_info = image_store[image_id]
    img_annotations = annotations.get(image_id, {})
    agg = aggregated_labels.get(image_id)

    return jsonify({
        "image_id": image_id,
        "filename": img_info["filename"],
        "uploaded_at": img_info["uploaded_at"],
        "annotations": img_annotations,
        "num_annotations": len(img_annotations),
        "aggregated_label": agg
    })


@app.route("/images/<image_id>", methods=["DELETE"])
def delete_image(image_id):
    """Delete an image and its annotations."""
    if image_id not in image_store:
        return jsonify({"error": "Image not found"}), 404

    with lock:
        del image_store[image_id]
        annotations.pop(image_id, None)
        aggregated_labels.pop(image_id, None)

    return jsonify({"message": f"Image {image_id} deleted successfully"})


@app.route("/annotations", methods=["POST"])
def submit_annotation():
    """Submit a label annotation for an image."""
    data = request.get_json()
    if not data:
        return jsonify({"error": "JSON body required"}), 400

    image_id = data.get("image_id")
    annotator_id = data.get("annotator_id")
    label = data.get("label")

    if not all([image_id, annotator_id, label]):
        return jsonify({"error": "image_id, annotator_id, and label are required"}), 400

    if image_id not in image_store:
        return jsonify({"error": "Image not found"}), 404

    label = str(label).strip()

    with lock:
        if image_id not in annotations:
            annotations[image_id] = {}

        is_update = annotator_id in annotations[image_id]
        annotations[image_id][annotator_id] = label
        label_classes.add(label)

        # Re-aggregate after new annotation
        agg_result = aggregate_labels_majority_vote(image_id)

    return jsonify({
        "message": "Annotation submitted successfully",
        "image_id": image_id,
        "annotator_id": annotator_id,
        "label": label,
        "is_update": is_update,
        "current_aggregation": agg_result
    }), 201


@app.route("/annotations/batch", methods=["POST"])
def submit_batch_annotations():
    """Submit multiple annotations at once."""
    data = request.get_json()
    if not data or "annotations" not in data:
        return jsonify({"error": "JSON body with 'annotations' list required"}), 400

    annotation_list = data["annotations"]
    results = []
    errors = []

    with lock:
        for i, ann in enumerate(annotation_list):
            image_id = ann.get("image_id")
            annotator_id = ann.get("annotator_id")
            label = ann.get("label")

            if not all([image_id, annotator_id, label]):
                errors.append({"index": i, "error": "Missing required fields"})
                continue

            if image_id not in image_store:
                errors.append({"index": i, "error": f"Image {image_id} not found"})
                continue

            label = str(label).strip()
            if image_id not in annotations:
                annotations[image_id] = {}

            annotations[image_id][annotator_id] = label
            label_classes.add(label)
            aggregate_labels_majority_vote(image_id)

            results.append({
                "index": i,
                "image_id": image_id,
                "annotator_id": annotator_id,
                "label": label
            })

    return jsonify({
        "submitted": len(results),
        "errors": len(errors),
        "results": results,
        "error_details": errors
    }), 201


