def get_annotations(image_id):
    """Get all annotations for an image."""
    if image_id not in image_store:
        return jsonify({"error": "Image not found"}), 404

    img_annotations = annotations.get(image_id, {})
    agg = aggregated_labels.get(image_id)

    return jsonify({
        "image_id": image_id,
        "annotations": img_annotations,
        "num_annotations": len(img_annotations),
        "aggregated_label": agg
    })


@app.route("/annotations/<image_id>/<annotator_id>", methods=["DELETE"])
def delete_annotation(image_id, annotator_id):
    """Delete a specific annotation."""
    if image_id not in image_store:
        return jsonify({"error": "Image not found"}), 404

    with lock:
        if image_id in annotations and annotator_id in annotations[image_id]:
            del annotations[image_id][annotator_id]
            # Re-aggregate
            if annotations[image_id]:
                aggregate_labels_majority_vote(image_id)
            else:
                aggregated_labels.pop(image_id, None)
            return jsonify({"message": "Annotation deleted"})
        else:
            return jsonify({"error": "Annotation not found"}), 404


